<span class="line"><span style="color:#CDD6F4;">            id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;"> serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">json!</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">next_id</span><span style="color:#9399B2;">()),</span></span>
