<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tools_result</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">tools</span><span style="color:#9399B2;">)</span></span>
